  1096вҶ’## 4.3 Run Assignment Optimizer
  1097вҶ’
  1098вҶ’### 4.3.1 Purpose
  1099вҶ’
  1100вҶ’Optimize daily train-to-route assignments for mileage balancing while respecting hard constraints (fitness, PM due, **unavailability**, **service demand**) and minimizing soft constraint penalties.
  1101вҶ’
  1102вҶ’### 4.3.2 Optimizer Service (TypeScript Wrapper)
  1103вҶ’
  1104вҶ’```typescript
  1105вҶ’interface OptimizerConfig {
  1106вҶ’  binaryPath: string;          // ./mms-optimizer
  1107вҶ’  maxSolveTimeSeconds: number; // 30
  1108вҶ’  numWorkers: number;          // 4
  1109вҶ’  timeoutMs: number;           // 60000
  1110вҶ’  fallbackEnabled: boolean;    // true
  1111вҶ’}
  1112вҶ’
  1113вҶ’class RunAssignmentOptimizer {
  1114вҶ’  private process: Subprocess | null = null;
  1115вҶ’  
  1116вҶ’  async optimize(input: OptimizerInput): Promise<OptimizerResult> {
  1117вҶ’    const startTime = Date.now();
  1118вҶ’    
  1119вҶ’    try {
  1120вҶ’      // Try C++ optimizer first
  1121вҶ’      const result = await this.runCppOptimizer(input);
  1122вҶ’      
  1123вҶ’      // Validate result
  1124вҶ’      if (result.status === 'INFEASIBLE' && this.config.fallbackEnabled) {
  1125вҶ’        this.logger.warn('C++ optimizer returned INFEASIBLE, using fallback');
  1126вҶ’        return await this.runFallbackOptimizer(input);
  1127вҶ’      }
  1128вҶ’      
  1129вҶ’      return result;
  1130вҶ’      
  1131вҶ’    } catch (error) {
  1132вҶ’      this.logger.error({ error }, 'C++ optimizer failed, using fallback');
  1133вҶ’      
  1134вҶ’      if (this.config.fallbackEnabled) {
  1135вҶ’        return await this.runFallbackOptimizer(input);
  1136вҶ’      }
  1137вҶ’      
  1138вҶ’      throw error;
  1139вҶ’    }
  1140вҶ’  }
  1141вҶ’  
  1142вҶ’  private async runCppOptimizer(input: OptimizerInput): Promise<OptimizerResult> {
  1143вҶ’    return new Promise((resolve, reject) => {
  1144вҶ’      const timeout = setTimeout(() => {
  1145вҶ’        this.process?.kill();
  1146вҶ’        reject(new Error('Optimizer timeout'));
  1147вҶ’      }, this.config.timeoutMs);
  1148вҶ’      
  1149вҶ’      this.process = Bun.spawn([this.config.binaryPath], {
  1150вҶ’        stdin: 'pipe',
  1151вҶ’        stdout: 'pipe',
  1152вҶ’        stderr: 'pipe'
  1153вҶ’      });
  1154вҶ’      
  1155вҶ’      // Write input
  1156вҶ’      const writer = this.process.stdin.getWriter();
  1157вҶ’      writer.write(new TextEncoder().encode(JSON.stringify(input) + '\n'));
  1158вҶ’      writer.close();
  1159вҶ’      
  1160вҶ’      // Read stdout (results)
  1161вҶ’      const results: any[] = [];
  1162вҶ’      const reader = this.process.stdout.getReader();
  1163вҶ’      const decoder = new TextDecoder();
  1164вҶ’      let buffer = '';
  1165вҶ’      
  1166вҶ’      const readStream = async () => {
  1167вҶ’        while (true) {
  1168вҶ’          const { done, value } = await reader.read();
  1169вҶ’          if (done) break;
  1170вҶ’          
  1171вҶ’          buffer += decoder.decode(value, { stream: true });
  1172вҶ’          const lines = buffer.split('\n');
  1173вҶ’          buffer = lines.pop() || '';
  1174вҶ’          
  1175вҶ’          for (const line of lines) {
  1176вҶ’            if (!line.trim()) continue;
  1177вҶ’            
  1178вҶ’            try {
  1179вҶ’              const msg = JSON.parse(line);
  1180вҶ’              
  1181вҶ’              if (msg.type === 'PROGRESS') {
  1182вҶ’                this.emitProgress(msg);
  1183вҶ’              } else if (msg.type === 'RESULT') {
  1184вҶ’                clearTimeout(timeout);
  1185вҶ’                resolve(this.mapResult(msg));
  1186вҶ’                return;
  1187вҶ’              }
  1188вҶ’            } catch (e) {
  1189вҶ’              this.logger.warn({ line }, 'Failed to parse optimizer output');
  1190вҶ’            }
  1191вҶ’          }
  1192вҶ’        }
  1193вҶ’      };
  1194вҶ’      
  1195вҶ’      // Read stderr (metrics/logs)
  1196вҶ’      this.readStderr(this.process.stderr);
  1197вҶ’      
  1198вҶ’      readStream().catch(reject);
  1199вҶ’      
  1200вҶ’      this.process.exited.then((code) => {
  1201вҶ’        clearTimeout(timeout);
  1202вҶ’        if (code !== 0 && results.length === 0) {
  1203вҶ’          reject(new Error(`Optimizer exited with code ${code}`));
  1204вҶ’        }
  1205вҶ’      });
  1206вҶ’    });
  1207вҶ’  }
  1208вҶ’  
  1209вҶ’  private async runFallbackOptimizer(input: OptimizerInput): Promise<OptimizerResult> {
  1210вҶ’    // TypeScript greedy fallback
  1211вҶ’    const assignments: Assignment[] = [];
  1212вҶ’    const unassigned: UnassignedTrain[] = [];
  1213вҶ’    const assignedTrainIds = new Set<string>();
  1214вҶ’    
  1215вҶ’    // Sort routes by priority (required trains desc)
  1216вҶ’    const sortedRoutes = [...input.routes].sort(
  1217вҶ’      (a, b) => b.required_trains - a.required_trains
  1218вҶ’    );
  1219вҶ’    
  1220вҶ’    // Sort trains by fitness and mileage balance
  1221вҶ’    const sortedTrains = [...input.trains]
  1222вҶ’      .filter(t => t.fitness_status === 'FIT')
  1223вҶ’      .sort((a, b) => {
  1224вҶ’        // Prioritize under-utilized trains
  1225вҶ’        const aBalance = a.current_mileage - a.target_mileage;
  1226вҶ’        const bBalance = b.current_mileage - b.target_mileage;
  1227вҶ’        return aBalance - bBalance;
  1228вҶ’      });
  1229вҶ’    
  1230вҶ’    for (const route of sortedRoutes) {
  1231вҶ’      let assigned = 0;
  1232вҶ’      
  1233вҶ’      for (const train of sortedTrains) {
  1234вҶ’        if (assigned >= route.required_trains) break;
  1235вҶ’        if (assignedTrainIds.has(train.id)) continue;
  1236вҶ’        
  1237вҶ’        // Check hard constraints
  1238вҶ’        const hardViolation = this.checkHardConstraints(train, route, input);
  1239вҶ’        if (hardViolation) {
  1240вҶ’          continue;
  1241вҶ’        }
  1242вҶ’        
  1243вҶ’        // Check fleet compatibility
  1244вҶ’        if (route.allowed_fleets.length > 0 && 
  1245вҶ’            !route.allowed_fleets.includes(train.fleet_id)) {
  1246вҶ’          continue;
  1247вҶ’        }
  1248вҶ’        
  1249вҶ’        // Assign
  1250вҶ’        assignments.push({
  1251вҶ’          train_id: train.id,
  1252вҶ’          route_id: route.id,
  1253вҶ’          score: this.calculateScore(train, route),
  1254вҶ’          explanation: [
  1255вҶ’            {
  1256вҶ’              constraint_type: 'SOFT',
  1257вҶ’              constraint_name: 'MILEAGE_BALANCE',
  1258вҶ’              impact: train.current_mileage - train.target_mileage,
  1259вҶ’              description: `Train is ${Math.abs(train.current_mileage - train.target_mileage)}km ${
  1260вҶ’                train.current_mileage < train.target_mileage ? 'under' : 'over'
  1261вҶ’              } target`
  1262вҶ’            }
  1263вҶ’          ]
  1264вҶ’        });
  1265вҶ’        
  1266вҶ’        assignedTrainIds.add(train.id);
  1267вҶ’        assigned++;
  1268вҶ’      }
  1269вҶ’      
  1270вҶ’      // Record shortfall
  1271вҶ’      if (assigned < route.required_trains) {
  1272вҶ’        unassigned.push({
  1273вҶ’          route_id: route.id,
  1274вҶ’          shortfall: route.required_trains - assigned,
  1275вҶ’          reason: 'Insufficient fit trains available'
  1276вҶ’        });
  1277вҶ’      }
  1278вҶ’    }
  1279вҶ’    
  1280вҶ’    // Record unassigned trains with reasons
  1281вҶ’    for (const train of input.trains) {
  1282вҶ’      if (assignedTrainIds.has(train.id)) continue;
  1283вҶ’      
  1284вҶ’      const reason = train.fitness_status !== 'FIT' 
