  1774вҶ’        trackAvailability,
  1775вҶ’        laborCapacity,
  1776вҶ’        materialPositions,
  1777вҶ’        scheduled
  1778вҶ’      );
  1779вҶ’      
  1780вҶ’      if (result.scheduled) {
  1781вҶ’        scheduled.push(result.scheduled);
  1782вҶ’        
  1783вҶ’        // Reserve materials
  1784вҶ’        await this.reserveMaterials(result.scheduled, materialPositions);
  1785вҶ’        
  1786вҶ’        // Update availability
  1787вҶ’        this.updateAvailability(
  1788вҶ’          result.scheduled,
  1789вҶ’          trackAvailability,
  1790вҶ’          laborCapacity
  1791вҶ’        );
  1792вҶ’      } else {
  1793вҶ’        deferred.push({
  1794вҶ’          pm,
  1795вҶ’          reason: result.reason,
  1796вҶ’          suggestedDate: result.suggestedDate
  1797вҶ’        });
  1798вҶ’      }
  1799вҶ’      
  1800вҶ’      if (result.materialWarning) {
  1801вҶ’        materialWarnings.push(result.materialWarning);
  1802вҶ’      }
  1803вҶ’    }
  1804вҶ’    
  1805вҶ’    // 5. Persist schedule
  1806вҶ’    await this.persistSchedule(scheduled, deferred);
  1807вҶ’    
  1808вҶ’    // 6. Notify if material blocks exist
  1809вҶ’    if (materialWarnings.length > 0) {
  1810вҶ’      await this.notifyMaterialBlocks(materialWarnings);
  1811вҶ’    }
  1812вҶ’    
  1813вҶ’    return {
  1814вҶ’      scheduled,
  1815вҶ’      deferred,
  1816вҶ’      materialWarnings,
  1817вҶ’      summary: {
  1818вҶ’        totalPMs: sortedPMs.length,
  1819вҶ’        scheduledCount: scheduled.length,
  1820вҶ’        deferredCount: deferred.length,
  1821вҶ’        trackUtilization: this.calculateTrackUtilization(trackAvailability),
  1822вҶ’        laborUtilization: this.calculateLaborUtilization(laborCapacity)
  1823вҶ’      }
  1824вҶ’    };
  1825вҶ’  }
  1826вҶ’  
  1827вҶ’  private async scheduleSinglePM(
  1828вҶ’    pm: PendingPM,
  1829вҶ’    trackAvailability: TrackAvailability[],
  1830вҶ’    laborCapacity: LaborCapacity[],
  1831вҶ’    materialPositions: MaterialPosition[],
  1832вҶ’    alreadyScheduled: ScheduledPM[]
  1833вҶ’  ): Promise<ScheduleAttemptResult> {
  1834вҶ’    const pmType = pm.pmType;
  1835вҶ’    
  1836вҶ’    // Find valid dates within compliance window
  1837вҶ’    const validDates = this.getValidDates(
  1838вҶ’      pm.constraintStart,
  1839вҶ’      pm.constraintEnd,
  1840вҶ’      pmType.minTrackDays
  1841вҶ’    );
  1842вҶ’    
  1843вҶ’    for (const targetDate of validDates) {
  1844вҶ’      // Check track availability
  1845вҶ’      const track = this.findAvailableTrack(
  1846вҶ’        targetDate,
  1847вҶ’        pmType.trackType,
  1848вҶ’        pmType.minTrackDays,
  1849вҶ’        trackAvailability
  1850вҶ’      );
  1851вҶ’      
  1852вҶ’      if (!track) continue;
  1853вҶ’      
  1854вҶ’      // Check labor capacity
  1855вҶ’      const laborOk = this.checkLaborCapacity(
  1856вҶ’        targetDate,
  1857вҶ’        pmType.estimatedHours,
  1858вҶ’        laborCapacity
  1859вҶ’      );
  1860вҶ’      
  1861вҶ’      if (!laborOk) continue;
  1862вҶ’      
  1863вҶ’      // Check material availability
  1864вҶ’      const materialCheck = await this.checkMaterialAvailability(
  1865вҶ’        pm,
  1866вҶ’        targetDate,
  1867вҶ’        materialPositions
  1868вҶ’      );
  1869вҶ’      
  1870вҶ’      if (materialCheck.blocked) {
  1871вҶ’        // Within hard constraint window - cannot schedule
  1872вҶ’        if (this.isWithinHardWindow(targetDate)) {
  1873вҶ’          return {
  1874вҶ’            scheduled: null,
  1875вҶ’            reason: `Material unavailable: ${materialCheck.missingParts.join(', ')}`,
  1876вҶ’            suggestedDate: materialCheck.suggestedDate,
  1877вҶ’            materialWarning: {
  1878вҶ’              pmId: pm.id,
  1879вҶ’              trainId: pm.trainId,
  1880вҶ’              missingParts: materialCheck.missingParts,
  1881вҶ’              expectedAvailability: materialCheck.expectedDelivery
  1882вҶ’            }
  1883вҶ’          };
  1884вҶ’        }
  1885вҶ’        // Soft constraint window - add warning but continue
  1886вҶ’        continue;
  1887вҶ’      }
  1888вҶ’      
  1889вҶ’      // Schedule found!
  1890вҶ’      return {
  1891вҶ’        scheduled: {
  1892вҶ’          pmId: pm.id,
  1893вҶ’          trainId: pm.trainId,
  1894вҶ’          pmTypeId: pmType.id,
  1895вҶ’          targetDate,
  1896вҶ’          trackId: track.id,
  1897вҶ’          assignedHours: pmType.estimatedHours,
  1898вҶ’          constraintStart: pm.constraintStart,
  1899вҶ’          constraintEnd: pm.constraintEnd
  1900вҶ’        },
  1901вҶ’        reason: null,
  1902вҶ’        materialWarning: materialCheck.warning
  1903вҶ’      };
  1904вҶ’    }
  1905вҶ’    
  1906вҶ’    // No valid slot found
  1907вҶ’    return {
  1908вҶ’      scheduled: null,
  1909вҶ’      reason: 'No available slot within compliance window',
  1910вҶ’      suggestedDate: addDays(pm.constraintEnd, 7)
  1911вҶ’    };
  1912вҶ’  }
  1913вҶ’  
  1914вҶ’  private async checkMaterialAvailability(
  1915вҶ’    pm: PendingPM,
  1916вҶ’    targetDate: Date,
  1917вҶ’    materialPositions: MaterialPosition[]
  1918вҶ’  ): Promise<MaterialCheckResult> {
  1919вҶ’    const requirements = await this.getPMRequirements(pm.pmType.id);
  1920вҶ’    const missingParts: string[] = [];
  1921вҶ’    let earliestDelivery: Date | null = null;
  1922вҶ’    
  1923вҶ’    for (const req of requirements) {
  1924вҶ’      if (req.criticality === 'CONSUMABLE') continue;
  1925вҶ’      
  1926вҶ’      const position = materialPositions.find(
  1927вҶ’        p => p.partNumber === req.partNumber && p.depotId === pm.depotId
  1928вҶ’      );
  1929вҶ’      
  1930вҶ’      const available = position?.quantityAvailable || 0;
  1931вҶ’      
  1932вҶ’      if (available < req.quantityPerPM) {
  1933вҶ’        if (req.criticality === 'BLOCKING') {
  1934вҶ’          missingParts.push(req.partNumber);
  1935вҶ’          
  1936вҶ’          if (position?.nextDeliveryDate) {
  1937вҶ’            const delivery = new Date(position.nextDeliveryDate);
  1938вҶ’            if (!earliestDelivery || delivery < earliestDelivery) {
  1939вҶ’              earliestDelivery = delivery;
  1940вҶ’            }
  1941вҶ’          }
  1942вҶ’        }
  1943вҶ’      }
  1944вҶ’    }
  1945вҶ’    
  1946вҶ’    return {
  1947вҶ’      blocked: missingParts.length > 0 && 
  1948вҶ’               this.isWithinHardWindow(targetDate),
  1949вҶ’      missingParts,
  1950вҶ’      expectedDelivery: earliestDelivery,
  1951вҶ’      suggestedDate: earliestDelivery 
  1952вҶ’        ? addDays(earliestDelivery, 1)
  1953вҶ’        : null,
  1954вҶ’      warning: missingParts.length > 0 ? {
  1955вҶ’        type: 'LOW_STOCK',
  1956вҶ’        parts: missingParts,
  1957вҶ’        message: `Parts may be unavailable: ${missingParts.join(', ')}`
  1958вҶ’      } : null
  1959вҶ’    };
  1960вҶ’  }
  1961вҶ’}
