  1989вҶ’  async movePM(
  1990вҶ’    pmId: string,
  1991вҶ’    newTargetDate: Date,
  1992вҶ’    newTrackId: string | null,
  1993вҶ’    userId: string
  1994вҶ’  ): Promise<PMScheduleRecord> {
  1995вҶ’    
  1996вҶ’    // 1. CRITICAL: Validate Maximo status lock
  1997вҶ’    const editValidation = await this.pmEditValidator.validateEdit(pmId);
  1998вҶ’    
  1999вҶ’    if (!editValidation.valid) {
  2000вҶ’      throw new PMEditBlockedError(
  2001вҶ’        editValidation.reason,
  2002вҶ’        editValidation.message,
  2003вҶ’        {
  2004вҶ’          maximoStatus: editValidation.maximoStatus,
  2005вҶ’          maximoWonum: editValidation.maximoWonum,
  2006вҶ’          suggestion: editValidation.suggestion
  2007вҶ’        }
  2008вҶ’      );
  2009вҶ’    }
  2010вҶ’    
  2011вҶ’    // 2. Load PM with all relationships
  2012вҶ’    const pm = await this.db.query.pmSchedule.findFirst({
  2013вҶ’      where: eq(pmSchedule.id, pmId),
  2014вҶ’      with: {
  2015вҶ’        pmType: true,
  2016вҶ’        train: true,
  2017вҶ’        assignedTrack: true
  2018вҶ’      }
  2019вҶ’    });
  2020вҶ’    
  2021вҶ’    if (!pm) {
  2022вҶ’      throw new NotFoundError('PM not found');
  2023вҶ’    }
  2024вҶ’    
  2025вҶ’    // 3. Validate compliance window
  2026вҶ’    if (newTargetDate < pm.constraintStart || newTargetDate > pm.constraintEnd) {
  2027вҶ’      throw new ComplianceWindowError(
  2028вҶ’        `Target date ${newTargetDate.toISOString().split('T')[0]} is outside compliance window`,
  2029вҶ’        {
  2030вҶ’          constraintStart: pm.constraintStart,
  2031вҶ’          constraintEnd: pm.constraintEnd,
  2032вҶ’          requestedDate: newTargetDate
  2033вҶ’        }
  2034вҶ’      );
  2035вҶ’    }
  2036вҶ’    
  2037вҶ’    // 4. Validate track availability (if track specified)
  2038вҶ’    if (newTrackId) {
  2039вҶ’      const conflict = await this.checkTrackConflict(
  2040вҶ’        newTrackId,
  2041вҶ’        newTargetDate,
  2042вҶ’        pm.pmType.minTrackDays,
  2043вҶ’        pmId  // Exclude self from conflict check
  2044вҶ’      );
