  2046вҶ’      if (conflict) {
  2047вҶ’        throw new TrackConflictError(
  2048вҶ’          `Track ${conflict.trackNumber} is occupied by ${conflict.conflictingPMCode}`,
  2049вҶ’          conflict
  2050вҶ’        );
  2051вҶ’      }
  2052вҶ’    }
  2053вҶ’    
  2054вҶ’    // 5. Capture old state for audit
  2055вҶ’    const oldState = {
  2056вҶ’      targetDate: pm.targetDate,
  2057вҶ’      assignedTrackId: pm.assignedTrackId
  2058вҶ’    };
  2059вҶ’    
  2060вҶ’    // 6. Update PM schedule
  2061вҶ’    const updatedPM = await this.db.transaction(async (tx) => {
  2062вҶ’      // Update main record
  2063вҶ’      const [updated] = await tx.update(pmSchedule)
  2064вҶ’        .set({
