  2068вҶ’        })
  2069вҶ’        .where(eq(pmSchedule.id, pmId))
  2070вҶ’        .returning();
  2071вҶ’      
  2072вҶ’      // Record in history table
  2073вҶ’      await tx.insert(pmScheduleHistory).values({
  2074вҶ’        pmScheduleId: pmId,
