  2095вҶ’      return updated;
  2096вҶ’    });
  2097вҶ’    
  2098вҶ’    // 7. Update shadow record for Maximo sync
  2099вҶ’    await this.updateShadowRecord(pmId, {
  2100вҶ’      syncStatus: 'PENDING',
  2101вҶ’      pendingChanges: {
  2102вҶ’        targetDate: newTargetDate.toISOString(),
  2103вҶ’        trackId: newTrackId
  2104вҶ’      }
  2105вҶ’    });
  2106вҶ’    
  2107вҶ’    // 8. Audit log
  2108вҶ’    await this.auditLogger.log({
  2109вҶ’      action: 'PM_RESCHEDULED',
  2110вҶ’      entityType: 'PM_SCHEDULE',
  2111вҶ’      entityId: pmId,
  2112вҶ’      userId,
  2113вҶ’      changes: {
