  2143вҶ’  /**
  2144вҶ’   * Check if a track has conflicts for the given date range.
  2145вҶ’   */
  2146вҶ’  private async checkTrackConflict(
  2147вҶ’    trackId: string,
  2148вҶ’    startDate: Date,
  2149вҶ’    durationDays: number,
  2150вҶ’    excludePmId?: string
  2151вҶ’  ): Promise<TrackConflict | null> {
  2152вҶ’    const endDate = addDays(startDate, durationDays);
  2153вҶ’    
  2154вҶ’    const conflictingPM = await this.db.query.pmSchedule.findFirst({
  2155вҶ’      where: and(
  2156вҶ’        eq(pmSchedule.assignedTrackId, trackId),
  2157вҶ’        excludePmId ? ne(pmSchedule.id, excludePmId) : undefined,
  2158вҶ’        or(
  2159вҶ’          // New PM overlaps existing PM's start
  2160вҶ’          and(
  2161вҶ’            lte(pmSchedule.targetDate, startDate),
  2162вҶ’            gte(sql`${pmSchedule.targetDate} + ${durationDays} * interval '1 day'`, startDate)
  2163вҶ’          ),
  2164вҶ’          // New PM overlaps existing PM's end
  2165вҶ’          and(
  2166вҶ’            lte(pmSchedule.targetDate, endDate),
  2167вҶ’            gte(sql`${pmSchedule.targetDate} + ${durationDays} * interval '1 day'`, startDate)
  2168вҶ’          )
  2169вҶ’        ),
  2170вҶ’        inArray(pmSchedule.status, ['SCHEDULED', 'IN_PROGRESS'])
  2171вҶ’      ),
  2172вҶ’      with: {
  2173вҶ’        pmType: true,
  2174вҶ’        train: true,
  2175вҶ’        assignedTrack: true
  2176вҶ’      }
  2177вҶ’    });
  2178вҶ’    
  2179вҶ’    if (conflictingPM) {
  2180вҶ’      return {
  2181вҶ’        trackId,
  2182вҶ’        trackNumber: conflictingPM.assignedTrack.trackNumber,
  2183вҶ’        conflictingPMId: conflictingPM.id,
  2184вҶ’        conflictingPMCode: conflictingPM.pmType.pmCode,
  2185вҶ’        conflictingTrainNumber: conflictingPM.train.trainNumber,
  2186вҶ’        conflictingDateRange: {
  2187вҶ’          start: conflictingPM.targetDate,
  2188вҶ’          end: addDays(conflictingPM.targetDate, conflictingPM.pmType.minTrackDays)
  2189вҶ’        }
  2190вҶ’      };
  2191вҶ’    }
  2192вҶ’    
  2193вҶ’    return null;
  2194вҶ’  }
  2195вҶ’}
