  2254вҶ’## 4.5 Strategic Planner
  2255вҶ’
  2256вҶ’### 4.5.1 Purpose
  2257вҶ’
  2258вҶ’Generate and maintain the 1-10 year strategic plan using genetic algorithms, constrained by capacity envelopes from the tactical model.
  2259вҶ’
  2260вҶ’### 4.5.2 Implementation
  2261вҶ’
  2262вҶ’```typescript
  2263вҶ’interface StrategicPlannerConfig {
  2264вҶ’  horizonYears: number;          // 10
  2265вҶ’  granularity: 'MONTHLY' | 'QUARTERLY';
  2266вҶ’  populationSize: number;        // 100
  2267вҶ’  generations: number;           // 500
  2268вҶ’  mutationRate: number;          // 0.1
  2269вҶ’  eliteCount: number;            // 10
  2270вҶ’}
  2271вҶ’
  2272вҶ’interface StrategicAllocation {
  2273вҶ’  trainId: string;
  2274вҶ’  pmTypeId: string;
  2275вҶ’  targetQuarter: string;  // e.g., '2028-Q2'
  2276вҶ’  estimatedHours: number;
  2277вҶ’  estimatedCost: number;
  2278вҶ’}
  2279вҶ’
  2280вҶ’class StrategicPlanner {
  2281вҶ’  private constraintAggregation: ConstraintAggregationService;
  2282вҶ’  
  2283вҶ’  async generatePlan(
  2284вҶ’    fromBaseline: string | null
  2285вҶ’  ): Promise<StrategicPlanResult> {
  2286вҶ’    // 1. Load current fleet state
  2287вҶ’    const fleetState = await this.getFleetState();
  2288вҶ’    
  2289вҶ’    // 2. Project PM requirements for each train
  2290вҶ’    const pmRequirements = await this.projectPMRequirements(
  2291вҶ’      fleetState,
  2292вҶ’      this.config.horizonYears
  2293вҶ’    );
  2294вҶ’    
  2295вҶ’    // 3. Generate constraint envelopes for each quarter
  2296вҶ’    const envelopes = await this.generateEnvelopes();
